import{_ as e,o as a,c as n,ag as r}from"./chunks/framework.gU7RhlGX.js";const l="/Awesome-AI-Pedia/assets/01-scene-rag-metaphor.BIoHkfp6.png",i="/Awesome-AI-Pedia/assets/02-flowchart-rag-workflow.BIadW0Qk.png",s="/Awesome-AI-Pedia/assets/03-comparison-rag-vs-finetuning.IsJMG59V.png",o="/Awesome-AI-Pedia/assets/04-infographic-rag-advantages.BOqlLKRX.png",f=JSON.parse('{"title":"RAG（检索增强生成）","description":"","frontmatter":{},"headers":[],"relativePath":"不可不知的Ai知识/RAG（检索增强生成）.md","filePath":"不可不知的Ai知识/RAG（检索增强生成）.md","lastUpdated":1776422487000}'),g={name:"不可不知的Ai知识/RAG（检索增强生成）.md"};function d(h,t,p,_,u,c){return a(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="rag-检索增强生成" tabindex="-1">RAG（检索增强生成） <a class="header-anchor" href="#rag-检索增强生成" aria-label="Permalink to &quot;RAG（检索增强生成）&quot;">​</a></h1><p>RAG（检索增强生成）是一种让大语言模型在回答问题时，能够先从外部知识库中<strong>检索相关信息</strong>，再基于这些信息生成答案的技术架构。</p><p>简单来说，<strong>RAG (Retrieval-Augmented Generation，检索增强生成)</strong> 是一种让大语言模型（LLM）通过“翻书”来回答问题的技术。</p><p>如果把大模型比作一个非常有才华但记忆力有限的”学霸”，RAG 就是给这位学霸配了一个<strong>实时更新的图书馆</strong>。当学霸遇到不确定的问题时，他会先去图书馆查阅相关资料，再结合自己的知识给出一个准确的答案。</p><p><img src="'+l+'" alt="RAG 核心隐喻：LLM 学霸与图书馆"></p><h3 id="_1-为什么需要-rag" tabindex="-1">1. 为什么需要 RAG？ <a class="header-anchor" href="#_1-为什么需要-rag" aria-label="Permalink to &quot;1. 为什么需要 RAG？&quot;">​</a></h3><ul><li><strong>幻觉问题</strong>：模型会一本正经地胡说八道。</li><li><strong>时效性滞后</strong>：模型的知识停留在训练数据截止日期（比如 2024 年或更早），不知道昨天发生的新闻。</li><li><strong>缺乏私域知识</strong>：模型没读过你公司的内部文档、私人笔记或特定行业的手册。</li></ul><ul><li><strong>可溯源</strong>：答案可以标注来源文档，方便核查，增强可信度。</li></ul><h3 id="_2-rag-的工作流程" tabindex="-1">2. RAG 的工作流程 <a class="header-anchor" href="#_2-rag-的工作流程" aria-label="Permalink to &quot;2. RAG 的工作流程&quot;">​</a></h3><p>RAG 的核心流程可以拆分为三个主要阶段：</p><p><img src="'+i+'" alt="RAG 三阶段工作流程"></p><h4 id="第一阶段-数据准备-indexing" tabindex="-1">第一阶段：数据准备（Indexing） <a class="header-anchor" href="#第一阶段-数据准备-indexing" aria-label="Permalink to &quot;第一阶段：数据准备（Indexing）&quot;">​</a></h4><ul><li><strong>切片</strong>：将长文档切成一小块一小块（Chunks）。</li><li><strong>向量化</strong>：将这些文字转化为机器能理解的数字向量（Embeddings）。</li><li><strong>存储</strong>：把这些向量存进“向量数据库”里。</li></ul><h4 id="第二阶段-检索-retrieval" tabindex="-1">第二阶段：检索（Retrieval） <a class="header-anchor" href="#第二阶段-检索-retrieval" aria-label="Permalink to &quot;第二阶段：检索（Retrieval）&quot;">​</a></h4><ul><li>当用户提问时，系统会把问题也转化为向量，然后在数据库里寻找<strong>内容最相关</strong>（Top-K ）的几个片段。</li></ul><h4 id="第三阶段-生成-generation" tabindex="-1">第三阶段：生成（Generation） <a class="header-anchor" href="#第三阶段-生成-generation" aria-label="Permalink to &quot;第三阶段：生成（Generation）&quot;">​</a></h4><ul><li>将这些文本块与原始问题拼接成完整的 Prompt，最后送入 LLM 生成答案</li></ul><h3 id="_3-rag-vs-微调-fine-tuning" tabindex="-1">3. RAG vs. 微调（Fine-tuning） <a class="header-anchor" href="#_3-rag-vs-微调-fine-tuning" aria-label="Permalink to &quot;3. RAG vs. 微调（Fine-tuning）&quot;">​</a></h3><p>这是很多人容易混淆的点。我们可以用一个形象的比喻：</p><p><img src="'+s+'" alt="RAG vs Fine-tuning 对比"></p><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">RAG（检索增强）</th><th style="text-align:left;">Fine-tuning（微调）</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>类比</strong></td><td style="text-align:left;"><strong>开卷考试</strong>（看资料回答）</td><td style="text-align:left;"><strong>闭卷考试</strong>（把知识背进脑子里）</td></tr><tr><td style="text-align:left;"><strong>知识更新</strong></td><td style="text-align:left;">极快（直接更新数据库即可）</td><td style="text-align:left;">慢且贵（需要重新训练）</td></tr><tr><td style="text-align:left;"><strong>准确性</strong></td><td style="text-align:left;">高（有据可查，减少幻觉）</td><td style="text-align:left;">中（容易受模型记忆偏差影响）</td></tr><tr><td style="text-align:left;"><strong>擅长领域</strong></td><td style="text-align:left;">处理事实性、动态更新的信息</td><td style="text-align:left;">学习特定的语气、格式或垂直领域逻辑</td></tr></tbody></table><h3 id="_4-rag-的优势" tabindex="-1">4. RAG 的优势 <a class="header-anchor" href="#_4-rag-的优势" aria-label="Permalink to &quot;4. RAG 的优势&quot;">​</a></h3><p><img src="'+o+'" alt="RAG 三大核心优势"></p><ul><li><strong>低成本</strong>：不需要动辄花费数万美金去训练模型。</li><li><strong>透明度</strong>：可以提供“引文”，告诉你答案是从哪个文档的哪一页来的。</li><li><strong>安全性</strong>：你可以轻松控制哪些数据可以被检索，保护隐私。</li></ul><h3 id="_5-进阶趋势" tabindex="-1">5. 进阶趋势 <a class="header-anchor" href="#_5-进阶趋势" aria-label="Permalink to &quot;5. 进阶趋势&quot;">​</a></h3><p>现在的 RAG 已经进化到了 <strong>Advanced RAG</strong> 阶段，引入了：</p><ul><li><strong>查询改写</strong>：如果用户问得模糊，系统先帮用户优化问题。</li><li><strong>重排序 (Rerank)</strong>：搜出一堆资料后，用另一个模型精挑细选最精准的。</li><li><strong>混合搜索</strong>：结合关键词搜索和语义搜索，确保万无一失。</li></ul><p><strong>常见应用场景</strong>：企业内部知识库问答、客服机器人、代码文档助手、学术文献检索等。</p>',28)])])}const m=e(g,[["render",d]]);export{f as __pageData,m as default};
